package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrim() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withTrim(true);

        // Then
        assertTrue(result.getTrim());
    }

    @Test
    public void testWithTrimFalse() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withTrim(false);

        // Then
        assertFalse(result.getTrim());
    }

    @Test
    public void testWithTrimUsingReflection() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat csvFormatSpy = spy(csvFormat);

        // When
        CSVFormat result = null;
        try {
            result = (CSVFormat) CSVFormat.class.getDeclaredMethod("withTrim", boolean.class)
                    .invoke(csvFormatSpy, true);
        } catch (Exception e) {
            fail("Exception thrown when invoking private method with reflection: " + e.getMessage());
        }

        // Then
        assertTrue(result.getTrim());
    }
}
